     1→/**
     2→ * TaskBar Component
     3→ * Draggable/resizable task bar for Gantt timeline
     4→ */
     5→
     6→import { useState, useRef, useEffect } from 'react';
     7→import type { Task, TaskPriority, BaselineTask } from '../../types';
     8→import { TASK_BAR_HEIGHT, type ZoomLevel, dateToX, xToDate, calculateBarWidth, isValidDateRange, snapToGrid } from './utils';
     9→import { calculateVarianceDays, getVarianceStatus } from '../../utils/baseline';
    10→
    11→interface TaskBarProps {
    12→  task: Task;
    13→  startDate: Date;
    14→  zoom: ZoomLevel;
    15→  rowY: number;
    16→  onUpdate: (taskId: string, updates: Partial<Task>) => void;
    17→  onClick: (task: Task) => void;
    18→  isCritical?: boolean; // Phase 1.3: Critical path indicator
    19→  baselineTask?: BaselineTask; // Phase 1.4: Baseline comparison
    20→  isSubtask?: boolean; // P2: Is this a subtask
    21→  isParent?: boolean; // P2: Is this a parent task with subtasks
    22→  isExpanded?: boolean; // P2: Is the parent task expanded
    23→  onToggleExpand?: () => void; // P2: Toggle expand/collapse
    24→  indentLevel?: number; // P2: Indentation level (0 = root, 1 = child, etc.)
    25→}
    26→
    27→export function TaskBar({
    28→  task,
    29→  startDate,
    30→  zoom,
    31→  rowY,
    32→  onUpdate,
    33→  onClick,
    34→  isCritical = false,
    35→  baselineTask,
    36→  isParent = false,
    37→  isExpanded = false,
    38→  onToggleExpand,
    39→  indentLevel = 0,
    40→}: TaskBarProps) {
    41→  const barRef = useRef<HTMLDivElement>(null);
    42→  const [isDragging, setIsDragging] = useState(false);
    43→  const [isResizing, setIsResizing] = useState(false);
    44→  const [dragStart, setDragStart] = useState({ x: 0, startDate: new Date(), dueDate: new Date() });
    45→
    46→  // Get task dates (use defaults if missing)
    47→  const taskStartDate = task.startDate ? new Date(task.startDate) : task.dueDate ? new Date(task.dueDate) : new Date();
    48→  const taskDueDate = task.dueDate ? new Date(task.dueDate) : task.startDate ? new Date(task.startDate) : new Date();
    49→
    50→  // Calculate bar position and width
    51→  const indentOffset = indentLevel * 20; // 20px per level
    52→  const x = dateToX(taskStartDate, startDate, zoom) + indentOffset;
    53→  const width = calculateBarWidth(taskStartDate, taskDueDate, zoom);
    54→  const y = rowY + (60 - TASK_BAR_HEIGHT) / 2; // Center in row
    55→
    56→  // Priority colors
    57→  const getPriorityColor = (priority: TaskPriority | undefined) => {
    58→    switch (priority) {
    59→      case 'high':
    60→        return 'bg-status-error text-white';
    61→      case 'medium':
    62→        return 'bg-accent-magenta dark:bg-accent-cyan text-white dark:text-dark-background';
    63→      case 'low':
    64→        return 'bg-status-info text-white';
    65→      default:
    66→        return 'bg-neutral-400 text-text-light-primary dark:text-text-dark-primary';
    67→    }
    68→  };
    69→
    70→  // Handle drag start
    71→  const handleDragStart = (e: React.MouseEvent) => {
    72→    if (isResizing) return;
    73→
    74→    e.preventDefault();
    75→    e.stopPropagation();
    76→
    77→    setIsDragging(true);
    78→    setDragStart({
    79→      x: e.clientX,
    80→      startDate: taskStartDate,
    81→      dueDate: taskDueDate,
    82→    });
    83→  };
    84→
    85→  // Handle resize start
    86→  const handleResizeStart = (e: React.MouseEvent) => {
    87→    e.preventDefault();
    88→    e.stopPropagation();
    89→
    90→    setIsResizing(true);
    91→    setDragStart({
    92→      x: e.clientX,
    93→      startDate: taskStartDate,
    94→      dueDate: taskDueDate,
    95→    });
    96→  };
    97→
    98→  // Global mouse move handler
    99→  useEffect(() => {
   100→    if (!isDragging && !isResizing) return;
   101→
   102→    const handleMouseMove = (e: MouseEvent) => {
   103→      const deltaX = e.clientX - dragStart.x;
   104→
   105→      if (isDragging) {
   106→        // Calculate new dates based on drag offset
   107→        const newStartDate = xToDate(dateToX(dragStart.startDate, startDate, zoom) + deltaX, startDate, zoom);
   108→        const newDueDate = xToDate(dateToX(dragStart.dueDate, startDate, zoom) + deltaX, startDate, zoom);
   109→
   110→        // Snap to grid
   111→        const snappedStart = snapToGrid(newStartDate);
   112→        const snappedDue = snapToGrid(newDueDate);
   113→
   114→        // Update task dates
   115→        if (isValidDateRange(snappedStart, snappedDue)) {
   116→          onUpdate(task.id, {
   117→            startDate: snappedStart.toISOString(),
   118→            dueDate: snappedDue.toISOString(),
   119→          });
   120→        }
   121→      } else if (isResizing) {
   122→        // Calculate new due date based on resize
   123→        const newDueDate = xToDate(dateToX(dragStart.dueDate, startDate, zoom) + deltaX, startDate, zoom);
   124→        const snappedDue = snapToGrid(newDueDate);
   125→
   126→        // Ensure valid range
   127→        if (isValidDateRange(dragStart.startDate, snappedDue)) {
   128→          onUpdate(task.id, {
   129→            dueDate: snappedDue.toISOString(),
   130→          });
   131→        }
   132→      }
   133→    };
   134→
   135→    const handleMouseUp = () => {
   136→      setIsDragging(false);
   137→      setIsResizing(false);
   138→    };
   139→
   140→    window.addEventListener('mousemove', handleMouseMove);
   141→    window.addEventListener('mouseup', handleMouseUp);
   142→
   143→    return () => {
   144→      window.removeEventListener('mousemove', handleMouseMove);
   145→      window.removeEventListener('mouseup', handleMouseUp);
   146→    };
   147→  }, [isDragging, isResizing, dragStart, task.id, startDate, zoom, onUpdate]);
   148→
   149→  // Phase 1.5: Progress percentage (0-100)
   150→  const progress = task.progress || 0;
   151→
   152→  // Get progress fill color (darker shade of bar color)
   153→  const getProgressFillColor = (priority: TaskPriority | undefined): string => {
   154→    if (isCritical) {
   155→      return 'rgba(220, 38, 38, 0.7)'; // Dark red for critical
   156→    }
   157→    switch (priority) {
   158→      case 'high':
   159→        return 'rgba(185, 28, 28, 0.8)'; // Darker red
   160→      case 'medium':
   161→        return 'rgba(157, 23, 77, 0.8)'; // Darker magenta
   162→      case 'low':
   163→        return 'rgba(30, 64, 175, 0.8)'; // Darker blue
   164→      default:
   165→        return 'rgba(115, 115, 115, 0.8)'; // Darker gray
   166→    }
   167→  };
   168→
   169→  // Phase 1.4: Calculate baseline variance
   170→  const varianceDays = baselineTask ? calculateVarianceDays(task, baselineTask) : null;
   171→  const varianceStatus = getVarianceStatus(varianceDays);
   172→
   173→  // Baseline bar positioning (if baseline exists)
   174→  let baselineX = 0;
   175→  let baselineWidth = 0;
   176→  if (baselineTask && (baselineTask.startDate || baselineTask.dueDate)) {
   177→    const baselineStartDate = baselineTask.startDate ? new Date(baselineTask.startDate) : baselineTask.dueDate ? new Date(baselineTask.dueDate) : new Date();
   178→    const baselineDueDate = baselineTask.dueDate ? new Date(baselineTask.dueDate) : baselineTask.startDate ? new Date(baselineTask.startDate) : new Date();
   179→    baselineX = dateToX(baselineStartDate, startDate, zoom);
   180→    baselineWidth = calculateBarWidth(baselineStartDate, baselineDueDate, zoom);
   181→  }
   182→
   183→  // Phase 1.6: Milestone rendering (diamond marker instead of bar)
   184→  if (task.isMilestone) {
   185→    const milestoneDate = task.dueDate ? new Date(task.dueDate) : new Date();
   186→    const milestoneX = dateToX(milestoneDate, startDate, zoom);
   187→    const milestoneY = rowY + (60 - 28) / 2; // Center 28px diagonal diamond
   188→
   189→    return (
   190→      <div
   191→        className="absolute cursor-pointer group"
   192→        style={{ left: milestoneX - 14, top: milestoneY }} // Center diamond on date
   193→        onClick={(e) => {
   194→          e.stopPropagation();
   195→          onClick(task);
   196→        }}
   197→      >
   198→        {/* Diamond marker (rotated square) */}
   199→        <div
   200→          className={`w-5 h-5 rotate-45 shadow-md border-2 transition-all group-hover:scale-110 ${
   201→            isCritical
   202→              ? 'bg-status-error border-status-error-border dark:border-status-error-border-dark'
   203→              : `border-border-light dark:border-border-dark ${getPriorityColor(task.priority)}`
   204→          }`}
